def table_exists(conn: sqlite3.Connection, table_name: str) -> bool:
    row = conn.execute(
        "SELECT 1 FROM sqlite_master WHERE type='table' AND name=?",
        (table_name,)
    ).fetchone()
    return row is not None


def column_exists(conn: sqlite3.Connection, table_name: str, column_name: str) -> bool:
    if not table_exists(conn, table_name):
        return False
    cols = [r[1] for r in conn.execute(f"PRAGMA table_info({table_name})").fetchall()]
    return column_name in cols


def ensure_column(conn: sqlite3.Connection, table: str, column_definition: str) -> None:
    """
    Agrega una columna a una tabla si no existe.
    column_definition: "nombre_columna TIPO DEFAULT valor"
    """
    col_name = column_definition.strip().split()[0]
    if not table_exists(conn, table):
        return
    if not column_exists(conn, table, col_name):
        try:
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {column_definition}")
        except Exception:
            pass


